import{_ as a,o as r,c as t,af as l}from"./chunks/framework.BSym9njW.js";const o="/hello-rocm/assets/amd_yes_project_overview_zh.DNaJ1n1K.webp",u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/05-amd-yes/index.md","filePath":"zh/05-amd-yes/index.md","lastUpdated":1783928033000}'),h={name:"zh/05-amd-yes/index.md"};function i(n,e,s,d,c,m){return r(),t("div",null,[...e[0]||(e[0]=[l('<div align="center"><h1>AMD-YES 🎮</h1><strong>玩转 AMD GPU 的酷炫项目合集</strong></div><div align="center"><p><em>让AI更有趣，让创意更自由</em> ✨</p><p><a href="/hello-rocm/zh/">返回主页</a></p></div><h2 id="🚀-快速导航" tabindex="-1">🚀 快速导航 <a class="header-anchor" href="#🚀-快速导航" aria-label="Permalink to &quot;🚀 快速导航&quot;">​</a></h2><table tabindex="0"><thead><tr><th>本地运行（单卡）</th><th>集群部署（多卡）</th></tr></thead><tbody><tr><td><a href="/hello-rocm/zh/05-amd-yes/toy-cli">🧸 toy-cli</a> ✅️</td><td><a href="/hello-rocm/zh/05-amd-yes/happy-llm/">🚀 happy-llm</a> ✅️</td></tr><tr><td><a href="/hello-rocm/zh/05-amd-yes/minesweeper-agent">💣 Minesweeper Agent</a> ✅️</td><td></td></tr><tr><td><a href="/hello-rocm/zh/05-amd-yes/wechat-jump">🎮 微信跳一跳</a> ✅️</td><td></td></tr><tr><td><a href="/hello-rocm/zh/05-amd-yes/huanhuan-chat">🎭 Chat-甄嬛</a> ✅️</td><td></td></tr><tr><td><a href="/hello-rocm/zh/05-amd-yes/hello-agents/">✈️ 智能旅行规划助手</a> ✅️</td><td></td></tr><tr><td><a href="/hello-rocm/zh/05-amd-yes/openclaw">🦞 OpenClaw 全隐私助手</a> ✅️</td><td></td></tr><tr><td><a href="/hello-rocm/zh/05-amd-yes/torch-rechub/">📚 Torch-RecHub 推荐系统实战</a> ✅️</td><td></td></tr><tr><td><a href="/hello-rocm/zh/05-amd-yes/every-embodied">🤖 Every Embodied 具身智能策略复刻</a> ✅️</td><td></td></tr></tbody></table><blockquote><p>✅ 支持 | 🚧 开发中</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>  AMD-YES 精选了一系列使用 AMD GPU 和 ROCm 平台的优秀项目实例。无论你是想快速体验大模型应用、学习计算机视觉、还是深入学习分布式训练，都能在这里找到合适的案例项目。</p><p>  本模块分为两个阶段：首先在本地单卡快速上手各类应用，然后进阶到集群部署和分布式训练。每个项目都包含完整的代码和详细的教程指导。</p><h3 id="amd-yes-项目学习路径" tabindex="-1">AMD-YES 项目学习路径 <a class="header-anchor" href="#amd-yes-项目学习路径" aria-label="Permalink to &quot;AMD-YES 项目学习路径&quot;">​</a></h3><div align="center"><img src="'+o+'" alt="图5.1 AMD-YES 项目学习路径总览" width="95%"></div><h2 id="项目列表" tabindex="-1">项目列表 <a class="header-anchor" href="#项目列表" aria-label="Permalink to &quot;项目列表&quot;">​</a></h2><h3 id="本地运行-单卡" tabindex="-1">本地运行（单卡） <a class="header-anchor" href="#本地运行-单卡" aria-label="Permalink to &quot;本地运行（单卡）&quot;">​</a></h3><p>适合个人开发者快速体验，一块 AMD 显卡就能玩转！</p><hr><h4 id="🧸-toy-cli-llm-轻量化终端助手" tabindex="-1">🧸 toy-cli - LLM 轻量化终端助手 <a class="header-anchor" href="#🧸-toy-cli-llm-轻量化终端助手" aria-label="Permalink to &quot;🧸 toy-cli - LLM 轻量化终端助手&quot;">​</a></h4><p><a href="https://github.com/KMnO4-zx/toy-cli" target="_blank" rel="noreferrer">toy-cli</a> 是一个简化的代码 Agent，提供极简的命令行调用大模型接口。</p><ul><li><strong>适合人群</strong>：初学者、想快速学习 API 调用的用户</li><li><strong>难度等级</strong>：⭐</li><li><strong>预计时间</strong>：30 分钟</li></ul><p>📖 <a href="/hello-rocm/zh/05-amd-yes/toy-cli">开始学习 toy-cli</a></p><hr><h4 id="💣-minesweeper-agent-用本地大模型玩扫雷" tabindex="-1">💣 Minesweeper Agent - 用本地大模型玩扫雷 <a class="header-anchor" href="#💣-minesweeper-agent-用本地大模型玩扫雷" aria-label="Permalink to &quot;💣 Minesweeper Agent - 用本地大模型玩扫雷&quot;">​</a></h4><p>本案例使用扫雷棋盘作为 Agent 的运行环境，通过 llama.cpp + Gemma 4 E4B 展示 Agent 的完整循环：观察、推理、工具调用、反馈。包含约束式 Agent 和自主式 Agent 两种模式的对比。</p><ul><li><strong>适合人群</strong>：想理解 Agent 核心循环和工程稳定性设计的开发者</li><li><strong>难度等级</strong>：⭐⭐</li><li><strong>预计时间</strong>：1 小时</li></ul><p>📖 <a href="/hello-rocm/zh/05-amd-yes/minesweeper-agent">开始学习 Minesweeper Agent</a></p><hr><h4 id="🎮-yolov10-微信跳一跳" tabindex="-1">🎮 YOLOv10 微信跳一跳 <a class="header-anchor" href="#🎮-yolov10-微信跳一跳" aria-label="Permalink to &quot;🎮 YOLOv10 微信跳一跳&quot;">​</a></h4><p><a href="https://github.com/KMnO4-zx/wechat-jump" target="_blank" rel="noreferrer">YOLOv10 微信跳一跳</a> 是基于 YOLOv10 目标检测的自动化游戏 AI，实时识别跳跃目标，精准计算距离。</p><ul><li><strong>适合人群</strong>：对计算机视觉和游戏 AI 感兴趣的开发者</li><li><strong>难度等级</strong>：⭐⭐</li><li><strong>预计时间</strong>：1 小时</li></ul><p>📖 <a href="/hello-rocm/zh/05-amd-yes/wechat-jump">开始学习微信跳一跳</a></p><hr><h4 id="🎭-chat-甄嬛-后宫语言模型" tabindex="-1">🎭 Chat-甄嬛 - 后宫语言模型 <a class="header-anchor" href="#🎭-chat-甄嬛-后宫语言模型" aria-label="Permalink to &quot;🎭 Chat-甄嬛 - 后宫语言模型&quot;">​</a></h4><p><a href="https://github.com/KMnO4-zx/huanhuan-chat" target="_blank" rel="noreferrer">Chat-甄嬛</a> 是基于《甄嬛传》台词训练的 LoRA 微调模型，完美模仿甄嬛的语气和说话风格。</p><ul><li><strong>适合人群</strong>：想学习模型微调和 LoRA 技术的开发者</li><li><strong>难度等级</strong>：⭐⭐</li><li><strong>预计时间</strong>：1.5 小时</li></ul><p>📖 <a href="/hello-rocm/zh/05-amd-yes/huanhuan-chat">开始学习 Chat-甄嬛</a></p><hr><h4 id="✈️-智能旅行规划助手" tabindex="-1">✈️ 智能旅行规划助手 <a class="header-anchor" href="#✈️-智能旅行规划助手" aria-label="Permalink to &quot;✈️ 智能旅行规划助手&quot;">​</a></h4><p><a href="/hello-rocm/zh/05-amd-yes/hello-agents/">智能旅行规划助手</a> 是基于 HelloAgents 框架的智能 Agent 应用，集成 MCP 协议调用高德地图 API，在 AMD GPU 上本地运行大模型。</p><ul><li><strong>适合人群</strong>：想学习 Agent 框架和 MCP 协议的开发者</li><li><strong>难度等级</strong>：⭐⭐⭐</li><li><strong>预计时间</strong>：2 小时</li></ul><p>📖 <a href="/hello-rocm/zh/05-amd-yes/hello-agents/smart-travel-planner/amd395-helloagents-smart-travel-planner">开始学习智能旅行规划助手</a></p><hr><h4 id="🦞-openclaw-全隐私本地-ai-智能体平台" tabindex="-1">🦞 OpenClaw - 全隐私本地 AI 智能体平台 <a class="header-anchor" href="#🦞-openclaw-全隐私本地-ai-智能体平台" aria-label="Permalink to &quot;🦞 OpenClaw - 全隐私本地 AI 智能体平台&quot;">​</a></h4><p><a href="https://github.com/ValueCell-ai/ClawX" target="_blank" rel="noreferrer">OpenClaw</a> 是一个统一的消息处理与 AI 智能体平台，在 AMD 395 Max 上本地部署大模型，实现完全隐私的个人 AI 助手。</p><ul><li><strong>适合人群</strong>：想学习 AI Agent 平台和本地隐私部署的开发者</li><li><strong>难度等级</strong>：⭐⭐⭐</li><li><strong>预计时间</strong>：1.5 小时</li></ul><p>📖 <a href="/hello-rocm/zh/05-amd-yes/openclaw">开始学习 OpenClaw</a></p><hr><h4 id="📚-torch-rechub-推荐系统实战" tabindex="-1">📚 Torch-RecHub - 推荐系统实战 <a class="header-anchor" href="#📚-torch-rechub-推荐系统实战" aria-label="Permalink to &quot;📚 Torch-RecHub - 推荐系统实战&quot;">​</a></h4><p><a href="https://github.com/datawhalechina/torch-rechub" target="_blank" rel="noreferrer">Torch-RecHub</a> 推荐系统实战教程覆盖 CTR 精排、序列兴趣建模、召回、多任务学习、实验跟踪和模型导出。</p><ul><li><strong>适合人群</strong>：想在 AMD GPU / ROCm 环境下学习推荐系统建模与训练流程的开发者</li><li><strong>难度等级</strong>：⭐⭐⭐</li><li><strong>预计时间</strong>：3 小时+</li></ul><p>📖 <a href="/hello-rocm/zh/05-amd-yes/torch-rechub/">开始学习 Torch-RecHub 推荐系统实战</a></p><hr><h4 id="🤖-every-embodied-rocm-具身智能策略复刻" tabindex="-1">🤖 Every Embodied - ROCm 具身智能策略复刻 <a class="header-anchor" href="#🤖-every-embodied-rocm-具身智能策略复刻" aria-label="Permalink to &quot;🤖 Every Embodied - ROCm 具身智能策略复刻&quot;">​</a></h4><p><a href="https://github.com/datawhalechina/every-embodied" target="_blank" rel="noreferrer">Every Embodied</a> 在 MuJoCo 桌面抓取任务中复刻 ACT、SmolVLA、Pi0 与 Pi0.5，覆盖数据采集、ROCm 训练、闭环部署、严格物理评估和失败诊断。</p><ul><li><strong>适合人群</strong>：想在 AMD GPU 上学习机器人模仿学习、VLA 和策略调试的开发者</li><li><strong>难度等级</strong>：⭐⭐⭐</li><li><strong>预计时间</strong>：按专题 Notebook 分阶段学习</li></ul><p>📖 <a href="/hello-rocm/zh/05-amd-yes/every-embodied">开始学习 Every Embodied ROCm 策略复刻</a></p><hr><h3 id="集群部署-多卡" tabindex="-1">集群部署（多卡） <a class="header-anchor" href="#集群部署-多卡" aria-label="Permalink to &quot;集群部署（多卡）&quot;">​</a></h3><p>进阶玩法，分布式训练部署！</p><hr><h4 id="🚀-happy-llm-从零训练大模型" tabindex="-1">🚀 Happy-LLM - 从零训练大模型 <a class="header-anchor" href="#🚀-happy-llm-从零训练大模型" aria-label="Permalink to &quot;🚀 Happy-LLM - 从零训练大模型&quot;">​</a></h4><p><a href="https://github.com/datawhalechina/happy-llm" target="_blank" rel="noreferrer">Happy-LLM</a> 提供分布式多机多卡训练的完整教程，包括大模型核心原理讲解和手把手的训练流程实现。</p><ul><li><strong>适合人群</strong>：想深入学习大模型训练的进阶开发者</li><li><strong>难度等级</strong>：⭐⭐⭐</li><li><strong>预计时间</strong>：3 小时+</li></ul><p>📖 <a href="/hello-rocm/zh/05-amd-yes/happy-llm/">开始学习 Happy-LLM</a></p><hr><h2 id="环境要求" tabindex="-1">环境要求 <a class="header-anchor" href="#环境要求" aria-label="Permalink to &quot;环境要求&quot;">​</a></h2><h3 id="硬件要求" tabindex="-1">硬件要求 <a class="header-anchor" href="#硬件要求" aria-label="Permalink to &quot;硬件要求&quot;">​</a></h3><ul><li>AMD GPU（支持 ROCm 的显卡，如 RX 7000 系列、MI 系列等）</li><li>建议显存 8GB 以上</li></ul><h3 id="软件要求" tabindex="-1">软件要求 <a class="header-anchor" href="#软件要求" aria-label="Permalink to &quot;软件要求&quot;">​</a></h3><ul><li>操作系统：Linux (Ubuntu 22.04+) 或 Windows 11</li><li>ROCm 7.12.0/7.2.0 或更高版本</li><li>Python 3.10~3.12</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><details><summary>Q: 如何确认我的 AMD GPU 是否支持 ROCm？</summary><p>请参考 <a href="https://rocm.docs.amd.com/projects/install-on-linux/en/latest/reference/system-requirements.html" target="_blank" rel="noreferrer">ROCm 官方支持列表</a> 查看支持的 GPU 型号。</p></details><details><summary>Q: 各个项目的学习顺序是什么？</summary><p>建议按以下顺序学习：</p><ol><li>先从 <code>toy-cli</code> 开始，熟悉大模型调用基础</li><li>选择感兴趣的案例深入学习（游戏 AI、对话模型、Agent 应用）</li><li>完成基础项目后，挑战 <code>Happy-LLM</code> 进阶分布式训练</li></ol></details><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><ul><li><a href="https://github.com/datawhalechina/self-llm" target="_blank" rel="noreferrer">self-llm 完整教程</a></li><li><a href="https://github.com/datawhalechina/hello-agents" target="_blank" rel="noreferrer">HelloAgents AI Agent 框架</a></li><li><a href="https://rocm.docs.amd.com/" target="_blank" rel="noreferrer">ROCm 官方文档</a></li><li><a href="./../">hello-rocm 主项目</a></li></ul><hr><div align="center"><p><strong>欢迎贡献更多项目案例！</strong> 🎉</p><p><a href="https://github.com/datawhalechina/hello-rocm/issues" target="_blank" rel="noreferrer">提交 Issue</a> | <a href="https://github.com/datawhalechina/hello-rocm/pulls" target="_blank" rel="noreferrer">提交 PR</a></p></div>',74)])])}const g=a(h,[["render",i]]);export{u as __pageData,g as default};
